#include <bits/stdc++.h>
using namespace std;

const int N=5e5+10;

vector<int> g[N];
int n,m,d[N],siz[N],dep[N],cnt,ans[N][2],root;
bool flag,b[N],c[N];

void dfsc(int x){
    c[x]=1;
    for(int i=0;i<g[x].size();i++)
        if(!c[g[x][i]] && dep[g[x][i]]>dep[x])
            dfsc(g[x][i]);
}

void dfs(int x){
    siz[x]=b[x]=1;
    for(int i=0;i<g[x].size() && !flag;i++)
        if(!b[g[x][i]]){
            dep[g[x][i]]=dep[x]+1;
            dfs(g[x][i]);
            if(x!=root && siz[g[x][i]]>1)
                flag=1,dfsc(g[x][i]);
            siz[x]+=siz[g[x][i]];
        }
}

int main(){
	memset(dep,0x3f,sizeof(dep)); 
    scanf("%d%d",&n,&m);
    for(int i=0,u,v;i<m;i++){
        scanf("%d%d",&u,&v);
        g[u].push_back(v),g[v].push_back(u);
        d[u]++,d[v]++;
    }
    int sum=0;
    for(int i=1;i<=n;i++)
        sum+=(d[i]>1);
    if(sum<2 || n<4){
        printf("-1");
        return 0;
    }
    for(int i=1;i<=n+1;i++){
    	if(d[i]==1){
    		dep[i]=1,root=i;
    		dfs(i);
    		break;
		}
		if(i==n+1){
    		dep[1]=1,root=1;
    		dfs(1);
    		break;
		}
	}
    for(int i=1;i<=n;i++)
        for(int j=0;j<g[i].size();j++)
            if(g[i][j]>i && c[g[i][j]]!=c[i])
                ans[++cnt][0]=i,ans[cnt][1]=g[i][j];
    printf("%d\n",cnt);
    for(int i=1;i<=cnt;i++)
        printf("%d %d\n",ans[i][0],ans[i][1]);
    return 0;
}
